mapper.select:
SELECT ci.*, c.coupon_nm, c.coupon_cd, c.coupon_type_cd, c.discount_rate, c.discount_amt, c.valid_from, c.valid_to, m.member_nm, m.member_email, cd_ct.code_label AS coupon_type_cd_nm FROM pm_coupon_issue ci LEFT JOIN pm_coupon c ON c.coupon_id = ci.coupon_id LEFT JOIN mb_member m ON m.member_id = ci.member_id LEFT JOIN sy_code cd_ct ON cd_ct.code_grp = 'COUPON_TYPE' AND cd_ct.code_value = c.coupon_type_cd
ORDER BY ci.issue_id ASC ORDER BY ci.issue_id DESC ORDER BY ci.issue_date ASC ORDER BY ci.issue_date DESC ORDER BY ci.issue_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT ci.*, c.coupon_nm, c.coupon_cd, c.coupon_type_cd, c.discount_rate, c.discount_amt, c.valid_from, c.valid_to, m.member_nm, m.member_email, cd_ct.code_label AS coupon_type_cd_nm FROM pm_coupon_issue ci LEFT JOIN pm_coupon c ON c.coupon_id = ci.coupon_id LEFT JOIN mb_member m ON m.member_id = ci.member_id LEFT JOIN sy_code cd_ct ON cd_ct.code_grp = 'COUPON_TYPE' AND cd_ct.code_value = c.coupon_type_cd
ORDER BY ci.issue_id ASC ORDER BY ci.issue_id DESC ORDER BY ci.issue_date ASC ORDER BY ci.issue_date DESC ORDER BY ci.issue_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

